from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/query_params_example')
def get_query_params():
    # request.args bir ImmutableMultiDict nesnesidir ve tüm query parametrelerini içerir.
    # Onu bir dictionary'ye çevirebilir veya doğrudan kullanabiliriz.
    params = request.args.to_dict()

    if not params:
        return jsonify({"message": "No query parameters provided."}), 200
    else:
        return jsonify({"received_parameters": params}), 200

if __name__ == '__main__':
    app.run(debug=True)
